import{_ as a,o as i,c as r,ag as t}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"DJI RC2 Reverse Engineering Research Notes","description":"Imported note from https://github.com/whitelewi1-ctrl/dji-rc2-research","frontmatter":{"title":"DJI RC2 Reverse Engineering Research Notes","description":"Imported note from https://github.com/whitelewi1-ctrl/dji-rc2-research"},"headers":[],"relativePath":"pen-testing/drones/github-dji-rc2-research.md","filePath":"pen-testing/drones/github-dji-rc2-research.md"}'),o={name:"pen-testing/drones/github-dji-rc2-research.md"};function n(s,e,l,c,d,h){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="dji-rc2-reverse-engineering-research-notes" tabindex="-1">DJI RC2 Reverse Engineering Research Notes <a class="header-anchor" href="#dji-rc2-reverse-engineering-research-notes" aria-label="Permalink to &quot;DJI RC2 Reverse Engineering Research Notes&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://github.com/whitelewi1-ctrl/dji-rc2-research" target="_blank" rel="noreferrer">https://github.com/whitelewi1-ctrl/dji-rc2-research</a></li><li>Imported: 2026-04-21</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>This repository documents hands-on reverse engineering of the DJI RC2 controller, including boot chain behavior, ADB hardening, DUML protocol observations, root workflow, framework patching, and recovery attempts after a severe boot failure.</p><h3 id="device-profile-and-platform-details" tabindex="-1">Device profile and platform details <a class="header-anchor" href="#device-profile-and-platform-details" aria-label="Permalink to &quot;Device profile and platform details&quot;">​</a></h3><ul><li>Device: DJI RC2 (<code>rc331</code>, internal codename <code>KATMAI-IDP</code>)</li><li>SoC/platform: Qualcomm QCS5430 (<code>lahaina</code> family), Android 11, kernel 5.4</li><li>Build characteristics include <code>test-keys</code> signing and a custom DJI Android stack</li><li>USB mode transitions expose multiple VID/PID states, including standard mode, ADB startup mode, and Qualcomm DIAG mode</li></ul><h3 id="usb-and-protocol-observations" tabindex="-1">USB and protocol observations <a class="header-anchor" href="#usb-and-protocol-observations" aria-label="Permalink to &quot;USB and protocol observations&quot;">​</a></h3><ul><li>In normal USB mode, vendor bulk interfaces provide bidirectional communication used for DJI DUML traffic.</li><li>ADB interface is present but consistently offline, even when system properties suggest ADB should be enabled.</li><li>DIAG mode can be enabled via internal tooling and exposes Qualcomm diagnostic interfaces.</li><li>DUML heartbeats and command responses were captured over USB bulk and selected Wi-Fi ports.</li></ul><h3 id="network-services-and-telemetry-channels" tabindex="-1">Network services and telemetry channels <a class="header-anchor" href="#network-services-and-telemetry-channels" aria-label="Permalink to &quot;Network services and telemetry channels&quot;">​</a></h3><ul><li>The controller exposes multiple TCP services after Wi-Fi connect, including DUML-like and proprietary binary streams.</li><li>High-rate sensor-style traffic (IMU-like payloads) is observed on one channel.</li><li>Additional channels carry RC status/control messages and mixed protocol frames.</li></ul><h3 id="security-model-findings" tabindex="-1">Security model findings <a class="header-anchor" href="#security-model-findings" aria-label="Permalink to &quot;Security model findings&quot;">​</a></h3><ul><li>The notes describe layered DJI defenses: <ul><li>Modified <code>adbd</code> behavior that refuses normal host connections</li><li>Interception of common bootloader entry paths</li><li>Runtime crypto checks tied to secure state</li><li>Network restrictions that limit common remote shell recovery paths</li></ul></li><li>The author reports many traditional bypass attempts failed (ADB key injection, wireless pairing, standard property toggles, and direct reboot flows).</li></ul><h3 id="root-and-system-modification-workflow" tabindex="-1">Root and system modification workflow <a class="header-anchor" href="#root-and-system-modification-workflow" aria-label="Permalink to &quot;Root and system modification workflow&quot;">​</a></h3><ul><li>Root was obtained using boot image extraction, Magisk patching, and flashing.</li><li>System-level exploration used internal DJI tooling and later user-installed tools.</li><li>Framework patching of <code>services.jar</code> was used to suppress DJI crypto warning overlays and bypass UI-side crypto checks.</li><li>Zygisk/LSPosed compatibility issues and policy workarounds are documented.</li></ul><h3 id="brick-incident-and-recovery-analysis" tabindex="-1">Brick incident and recovery analysis <a class="header-anchor" href="#brick-incident-and-recovery-analysis" aria-label="Permalink to &quot;Brick incident and recovery analysis&quot;">​</a></h3><ul><li>After installing an extracted DJI Fly package and triggering update behavior, device boot became stuck at logo stage.</li><li>Software recovery channels reportedly failed: <ul><li>ADB remained offline</li><li>DJI Assistant could not attach due to missing expected communication mode</li><li>Standard key combos and USB-based recovery scripts did not restore operability</li></ul></li><li>The write-up concludes software paths were exhausted and highlights physical recovery (test points / EDL) or vendor service as remaining options.</li></ul><h3 id="research-artifacts" tabindex="-1">Research artifacts <a class="header-anchor" href="#research-artifacts" aria-label="Permalink to &quot;Research artifacts&quot;">​</a></h3><ul><li>Repository includes scripts for DUML probing, USB endpoint testing, startup capture automation, and traffic differential analysis.</li><li>Notes also include observations on partitioning, DJI-specific binaries, hidden vendor apps, and firmware package structures.</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>DJI RC2 appears to implement strong practical hardening around ADB and boot/recovery pathways.</li><li>DUML and related vendor transport channels remain primary protocol-level research surfaces.</li><li>Root access and framework patching can change UX behavior but do not eliminate deeper secure-state checks.</li><li>Firmware/app update operations on modified systems can lead to unrecoverable boot states without physical intervention.</li></ul>',21)])])}const m=a(o,[["render",n]]);export{p as __pageData,m as default};
